def sum_fibonacci(n):
    """
    Calculate the sum of the first n Fibonacci numbers.
    Inspired by Malba Tahan's mathematical puzzles and storytelling.
    """
    if n <= 0:
        return 0
    elif n == 1:
        return 1

    fib_sequence = [0, 1]
    for i in range(2, n):
        fib_sequence.append(fib_sequence[-1] + fib_sequence[-2])

    return sum(fib_sequence)

# Example usage:
print(sum_fibonacci(5))  # Output: 7 (0 + 1 + 1 + 2 + 3)
